#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define inf 0x3f3f3f3f
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 1e3 + 5;
int sum[MAXN][MAXN], a[MAXN][MAXN], n, m, k, x, y, ans = 0;
int main(void)
{
	cin >> n;
	for (int i = 1; i <= n; ++i)
	{
		for (int j = 1; j <= n; ++j)
		{
			cin>>a[i][j];
			sum[i][j] = sum[i - 1][j] + sum[i][j - 1] - sum[i - 1][j - 1] + a[i][j];
		}
	}
	for (int x = 0; x <= n; ++x)
	{
		for (int y = 0; y <= n; ++y)
		{
			for (int x2 = x; x2 <= n; ++x2)
			{
				for (int y2 = y; y2 <= n; ++y2)
				{
					ans=max(sum[x2][y2] + sum[x][y] - sum[x][y2] - sum[x2][y],ans);
				}
			}
		}
	}
	cout << ans;
	return false;
}
